function addTwoNumbers(l1, l2) {
  const result = [];
  let carry = 0;
  let i = 0;
  while (i < l1.length || i < l2.length || carry > 0) {
    const a = i < l1.length ? l1[i] : 0;
    const b = i < l2.length ? l2[i] : 0;
    const sum = a + b + carry;
    result.push(sum % 10);
    carry = Math.floor(sum / 10);
    i++;
  }
  return result;
}
